import React, { useState, useEffect } from 'react';
import { Question, NodeType } from '../types';
import { X, CheckCircle, XCircle, Eye, Bot, Sparkles, Youtube, Skull, Shield, Zap, Clock } from 'lucide-react';
import { auth, getInventory, updateInventory } from '../utils/storage';

interface QuestionModalProps {
  question: Question;
  onAnswer: (isCorrect: boolean) => void;
  onClose: () => void;
  isReview?: boolean;
  nodeType?: NodeType;
}

const QuestionModal: React.FC<QuestionModalProps> = ({ question, onAnswer, onClose, isReview = false, nodeType = NodeType.NORMAL }) => {
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [shieldActive, setShieldActive] = useState(false);
  const [inventory, setInventory] = useState({ coins: 0, items: {} as any });

  const isBoss = nodeType === NodeType.BOSS;

  useEffect(() => {
    const loadInv = async () => {
        const user = auth.getCurrentUser();
        if (user) {
            const inv = await getInventory(user.username);
            setInventory(inv);
        }
    };
    loadInv();
  }, [question.id]);

  const useShield = async () => {
    if (inventory.items['SHIELD'] > 0 && !shieldActive) {
        setShieldActive(true);
        const user = auth.getCurrentUser();
        if (user) {
            const newInv = { ...inventory };
            newInv.items['SHIELD'] -= 1;
            await updateInventory(user.username, newInv);
            setInventory(newInv);
        }
    }
  };

  const handleSubmit = () => {
    if (selectedOption === null) return;
    setIsSubmitted(true);
  };

  const handleNext = () => {
    const isCorrect = selectedOption === question.correctAnswerIndex;
    if (!isCorrect && shieldActive) {
        // Shield saves the user - it counts as correct for the maze progression but no score? 
        // Or just let them retry. For simplicity: shield prevents heart loss.
        onAnswer(true); 
    } else {
        onAnswer(isCorrect);
    }
  };

  const isCorrect = selectedOption === question.correctAnswerIndex;

  return (
    <div className={`fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-md transition-all ${isBoss ? 'animate-shake' : ''}`}>
      <div className={`w-full max-w-3xl rounded-3xl shadow-2xl overflow-hidden border transition-all duration-500 ${isBoss ? 'bg-red-950 border-red-500 shadow-[0_0_80px_rgba(239,68,68,0.4)]' : 'bg-surface border-border'}`}>

        {/* Header */}
        <div className={`px-6 py-4 flex justify-between items-center border-b ${isBoss ? 'border-red-800 bg-red-900/40' : 'bg-background'}`}>
          <div className="flex items-center gap-3">
             {isBoss && <div className="p-2 bg-red-600 text-white rounded-xl animate-pulse"><Skull size={24}/></div>}
             <div>
                <h3 className={`font-bold ${isBoss ? 'text-white' : 'text-text'}`}>
                   {isBoss ? 'TRẬN CHIẾN BOSS CUỐI' : `Câu hỏi ${question.id}`}
                </h3>
                <p className={`text-xs uppercase tracking-wider ${isBoss ? 'text-red-300' : 'text-muted'}`}>{question.topic}</p>
             </div>
          </div>
          <div className="flex gap-2">
             {!isSubmitted && !isReview && (
                 <button 
                    onClick={useShield}
                    disabled={shieldActive || !inventory.items['SHIELD']}
                    className={`p-2 rounded-xl border flex items-center gap-2 transition-all ${shieldActive ? 'bg-blue-600 border-blue-400 text-white' : 'bg-surface border-border hover:border-blue-500 text-blue-600'}`}
                 >
                    <Shield size={18} className={shieldActive ? 'animate-bounce' : ''}/>
                    <span className="text-xs font-bold">{shieldActive ? 'ĐÃ KÍCH HOẠT' : inventory.items['SHIELD'] || 0}</span>
                 </button>
             )}
             <button onClick={onClose} className="p-2 text-muted hover:text-text"><X size={20}/></button>
          </div>
        </div>

        {/* Question Body */}
        <div className="p-8 max-h-[70vh] overflow-y-auto custom-scrollbar">
           <h2 className={`text-2xl font-bold mb-8 leading-snug ${isBoss ? 'text-red-50' : 'text-text'}`}>{question.text}</h2>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {question.options.map((opt, i) => (
                  <button
                    key={i}
                    onClick={() => !isSubmitted && setSelectedOption(i)}
                    className={`p-5 rounded-2xl border-2 text-left transition-all relative group overflow-hidden ${
                        isSubmitted 
                        ? i === question.correctAnswerIndex 
                          ? 'border-success bg-success/10' 
                          : i === selectedOption ? 'border-danger bg-danger/10' : 'border-border opacity-40'
                        : selectedOption === i 
                          ? isBoss ? 'border-red-400 bg-red-900/50 text-white' : 'border-primary bg-primary/5'
                          : isBoss ? 'border-red-900/50 bg-black/20 text-red-200 hover:border-red-700' : 'border-border hover:border-primary/50'
                    }`}
                  >
                     <div className="flex items-center gap-4 relative z-10">
                        <span className={`w-8 h-8 rounded-full flex items-center justify-center font-bold border-2 ${selectedOption === i ? 'bg-current text-white' : 'text-muted border-border'}`}>
                            {String.fromCharCode(65 + i)}
                        </span>
                        <span className="font-medium">{opt}</span>
                     </div>
                  </button>
              ))}
           </div>
        </div>

        {/* Footer */}
        <div className={`p-6 border-t flex justify-end items-center gap-4 ${isBoss ? 'border-red-800 bg-red-900/20' : 'bg-background'}`}>
           {isBoss && <div className="mr-auto text-red-400 text-xs font-bold animate-pulse flex items-center gap-2">
              <Zap size={14}/> SÁT THƯƠNG BOSS GẤP ĐÔI NẾU TRẢ LỜI ĐÚNG!
           </div>}

           {!isSubmitted ? (
             <button
               onClick={handleSubmit}
               disabled={selectedOption === null}
               className={`px-10 py-3 rounded-2xl font-bold text-lg shadow-xl transition-all active:scale-95 disabled:opacity-50 ${isBoss ? 'bg-red-600 text-white hover:bg-red-500 shadow-red-600/20' : 'btn-primary shadow-primary/20'}`}
             >
               XÁC NHẬN
             </button>
           ) : (
             <button
               onClick={handleNext}
               className={`px-10 py-3 rounded-2xl font-bold text-lg text-white transition-all ${isCorrect ? 'bg-success hover:bg-success/90' : 'bg-danger hover:bg-danger/90'}`}
             >
               {isCorrect ? 'TIẾP TỤC' : shieldActive ? 'KHIÊN ĐÃ ĐỠ!' : 'THỬ LẠI'}
             </button>
           )}
        </div>
      </div>
    </div>
  );
};

