import { GoogleGenAI, Type, Schema, Chat, Modality } from "@google/genai";
import { Difficulty, Question, Grade, Subject } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const questionSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    questions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          text: { type: Type.STRING },
          options: { type: Type.ARRAY, items: { type: Type.STRING } },
          correctAnswerIndex: { type: Type.INTEGER },
          explanation: { type: Type.STRING },
          topic: { type: Type.STRING }
        },
        required: ["id", "text", "options", "correctAnswerIndex", "explanation", "topic"]
      }
    }
  }
};

const cleanJson = (text: string): string => {
  const match = text.match(/\{[\s\S]*\}/);
  return match ? match[0] : text;
};

// Sử dụng Pro model với Thinking cho các câu hỏi quan trọng (Boss hoặc Hard)
export const generateMazeQuestions = async (grade: Grade, subject: Subject, difficulty: Difficulty, count: number): Promise<Question[]> => {
  const isHard = difficulty === Difficulty.HARD || count > 9;
  const model = isHard ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const prompt = `Bạn là chuyên gia giáo dục. Tạo ${count} câu hỏi trắc nghiệm lớp ${grade}, môn ${subject}, mức độ ${difficulty}. 
  Đảm bảo câu hỏi bám sát chương trình học và có lời giải chi tiết. Trả về JSON theo định dạng schema.`;

  const response = await ai.models.generateContent({
    model: model,
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: questionSchema,
      ...(isHard ? { thinkingConfig: { thinkingBudget: 32768 } } : {})
    }
  });

  return JSON.parse(cleanJson(response.text)).questions;
};

// Giải thích chuyên sâu dùng Thinking Mode
export const getDeepExplanation = async (question: Question, userAnswer: string): Promise<string> => {
  const prompt = `Câu hỏi: ${question.text}
  Đáp án đúng: ${question.options[question.correctAnswerIndex]}
  Học sinh chọn: ${userAnswer}
  Hãy phân tích sâu lỗi sai của học sinh, giải thích kiến thức nền tảng và cung cấp mẹo nhớ lâu.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 32768 }
    }
  });

  return response.text || "Không thể tải lời giải chuyên sâu lúc này.";
};

