          <div className="flex items-center gap-3">
             {isBoss && <Skull className="text-red-500 animate-pulse" size={24}/>}
             <h3 className={`font-bold ${isBoss ? 'text-white' : ''}`}>
               {isBoss ? 'THỬ THÁCH BOSS' : `Phòng số ${question.id}`}
             </h3>
          </div>
          <div className="flex items-center gap-4">
              <button 
                onClick={handleAskAI}
                disabled={isThinking}
                className="flex items-center gap-2 px-3 py-1.5 bg-purple-100 text-purple-700 rounded-xl text-xs font-bold hover:bg-purple-200 transition-colors disabled:opacity-50"
              >
                {isThinking ? <Loader2 size={14} className="animate-spin"/> : <Brain size={14}/>}
                TƯ DUY SÂU (50 xu)
              </button>
              <button onClick={onClose} className="text-muted hover:text-text"><X size={20}/></button>
          </div>
        </div>

        <div className="p-8 max-h-[70vh] overflow-y-auto custom-scrollbar">
           <h2 className={`text-xl font-bold mb-8 leading-snug ${isBoss ? 'text-red-50' : ''}`}>{question.text}</h2>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {question.options.map((opt, i) => (
                  <button
                    key={i}
                    disabled={isSubmitted || isReview}
                    onClick={() => setSelectedOption(i)}
                    className={`p-5 rounded-2xl border-2 text-left transition-all ${
                        isSubmitted || isReview
                        ? i === question.correctAnswerIndex 
                          ? 'border-success bg-success/10' 
                          : i === selectedOption ? 'border-danger bg-danger/10' : 'border-border opacity-50'
                        : selectedOption === i 
                          ? 'border-primary bg-primary/5' 
                          : 'border-border hover:border-primary/50'
                    }`}
                  >
                    <span className="font-medium">{opt}</span>
                  </button>
              ))}
           </div>

           {(isSubmitted || isReview || deepHelp) && (
             <div className="mt-8 p-6 bg-blue-50 dark:bg-blue-900/20 rounded-2xl border border-blue-100 animate-in fade-in slide-in-from-bottom duration-500">
                <div className="flex items-center gap-2 mb-3 text-blue-600 font-bold">
                    <Sparkles size={20}/>
                    <span>{deepHelp ? 'AI Tư Duy Sâu Phân Tích:' : 'Giải thích nhanh:'}</span>
                </div>
                <div className="text-sm leading-relaxed text-text whitespace-pre-wrap">
                    {deepHelp || question.explanation}
                </div>
             </div>
           )}
        </div>

        <div className="p-6 border-t border-border flex justify-end gap-3 bg-background/50">
           {!isSubmitted && !isReview ? (
             <button
               onClick={() => setIsSubmitted(true)}
               disabled={selectedOption === null}
               className="btn-primary px-10 py-3 rounded-2xl font-bold disabled:opacity-50"
             >
               XÁC NHẬN
             </button>
           ) : (
             <button
               onClick={() => onAnswer(isCorrect)}
               className={`px-10 py-3 rounded-2xl font-bold text-white ${isCorrect ? 'bg-success' : 'bg-danger'}`}
             >
               {isCorrect ? 'TIẾP TỤC' : 'THỬ LẠI'}
             </button>
           )}
        </div>
      </div>
    </div>
  );
};

