  title: string;
  content: string;
}

export interface StudyGuide {
  id: string;
  grade: Grade;
  subject: Subject;
  semester: 1 | 2;
  lessons: Lesson[];
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using plain object for schema as Schema type is not available from @google/genai
const questionSchema = {
  type: Type.OBJECT,
  properties: {
    questions: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          text: { type: Type.STRING },
          options: { type: Type.ARRAY, items: { type: Type.STRING } },
          correctAnswerIndex: { type: Type.INTEGER },
          explanation: { type: Type.STRING },
          topic: { type: Type.STRING }
        },
        required: ["id", "text", "options", "correctAnswerIndex", "explanation", "topic"]
      }
    }
  }
};

const cleanJson = (text: string): string => {
  const match = text.match(/\{[\s\S]*\}/);
  return match ? match[0] : text;
};

// Sử dụng Pro model với Thinking cho các câu hỏi quan trọng (Boss hoặc Hard)
export const generateMazeQuestions = async (grade: Grade, subject: Subject, difficulty: Difficulty, count: number): Promise<Question[]> => {
  const isHard = difficulty === Difficulty.HARD || count > 9;
  const model = isHard ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  const prompt = `Bạn là chuyên gia giáo dục. Tạo ${count} câu hỏi trắc nghiệm lớp ${grade}, môn ${subject}, mức độ ${difficulty}. 
  Đảm bảo câu hỏi bám sát chương trình học và có lời giải chi tiết. Trả về JSON theo định dạng schema.`;

  const response = await ai.models.generateContent({
    model: model,
    contents: prompt,
    config: { 
      responseMimeType: "application/json", 
      responseSchema: questionSchema,
      ...(isHard ? { thinkingConfig: { thinkingBudget: 32768 } } : {})
    }
  });

  return JSON.parse(cleanJson(response.text)).questions;
};

// Giải thích chuyên sâu dùng Thinking Mode
export const getDeepExplanation = async (question: Question, userAnswer: string): Promise<string> => {
  const prompt = `Câu hỏi: ${question.text}
  Đáp án đúng: ${question.options[question.correctAnswerIndex]}
  Học sinh chọn: ${userAnswer}
  Hãy phân tích sâu lỗi sai của học sinh, giải thích kiến thức nền tảng và cung cấp mẹo nhớ lâu.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 32768 }
    }
  });

  return response.text || "Không thể tải lời giải chuyên sâu lúc này.";
};

export const createLessonChatSession = (grade: Grade, subject: Subject, lessonTitle: string, lessonContent: string): Chat => {
  return ai.chats.create({
    model: "gemini-3-pro-preview",
    config: {
      systemInstruction: `Bạn là Gia sư AI MazeMind bậc thầy môn ${subject} lớp ${grade}. 
      Nhiệm vụ: Giải thích các khái niệm khó bằng cách chia nhỏ chúng. Luôn khuyến khích học sinh.
      Bạn có khả năng suy nghĩ sâu để giải quyết các vấn đề phức tạp.
      Nội dung bài học hiện tại: ${lessonTitle} - ${lessonContent}`,
      thinkingConfig: { thinkingBudget: 32768 }
    },
  });
};

// TTS vẫn dùng Flash để đảm bảo tốc độ
export const generateSpeech = async (text: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Đọc bài giảng sau bằng tiếng Việt: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const decode = (base64: string) => {
      const binaryString = atob(base64);
      const bytes = new Uint8Array(binaryString.length);
      for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
      return bytes;
    };

    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    const dataInt16 = new Int16Array(decode(base64Audio).buffer);
    const buffer = audioContext.createBuffer(1, dataInt16.length, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;

    const source = audioContext.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContext.destination);
    return source;
  } catch (err) {
    console.error("TTS Error", err);
    return null;
  }
};
